mapper.select:
SELECT id, shop_id, name, created_at, updated_at
FROM stock_location
WHERE shop_id = #{shopId} AND id = #{id}

SELECT shop_id, variant_id, location_id, available, reserved, updated_at
FROM stock_level
WHERE shop_id = #{shopId} AND variant_id = #{variantId} AND location_id = #{locationId}

mapper.update:
UPDATE stock_level
SET available = #{available}, reserved = #{reserved}, updated_at = #{updatedAt}
WHERE shop_id = #{shopId} AND variant_id = #{variantId} AND location_id = #{locationId}

mapper.select:
SELECT id, shop_id, variant_id, location_id, quantity, status, expires_at, created_at, updated_at
FROM stock_reservation
WHERE shop_id = #{shopId} AND id = #{id}

mapper.update:
UPDATE stock_reservation
SET status = #{status}, updated_at = #{updatedAt}
WHERE shop_id = #{shopId} AND id = #{id}
